{
  "title": "कमांड सबस्टीट्यूशन",
  "group": "ट्रिकी बातें",
  "options": [
    {
      "text": "'ls -l'"
    },
    {
      "text": "% ls -l"
    },
    {
      "text": "$ ls -l"
    },
    {
      "text": "$(ls -l)"
    },
    {
      "text": "${ls -l}"
    }
  ],
  "questionProse": [
    "इनमें से कौन सा विकल्प `ls -l` कमांड को एक्जीक्यूट करके उसका आउटपुट वापस करेगा?"
  ],
  "explanationProse": [
    "`$(ls -l)` सिंटैक्स **ब्रैकेट्स** के अंदर वाले कमांड को एक्जीक्यूट करता है और उसका आउटपुट सबस्टीट्यूट कर देता है। उदाहरण के लिए:\nपहला विकल्प सिंगल क्वोट्स `'` का उपयोग करता है, **बैकटिक्स का नहीं।** इससे एक्सपेंशन रोक दिया जाता है, इसलिए `'$(date +%F)'` सिर्फ एक लिटरल स्ट्रिंग `$(date +%F)` ही प्रिंट करेगा。\n\n    हालांकि बैकटिक्स (`` `ls -l` ``) से कमांड चलाना अभी भी सपोर्टेड है, लेकिन इसे हाल ही में एंटी-पैटर्न माना जाने लगा है। बेहतर रीडेबिलिटी और अलग-अलग शेल व वर्जन के साथ कंसिस्टेंसी के लिए `$(command)` का ही इस्तेमाल करें。\n\n    कर्ली ब्रेसिज़ `${}` वेरिएबल एक्सपैंड करने के लिए होते हैं, कमांड सबस्टीट्यूशन के लिए नहीं。\n\n    `%` चरित्र का इस्तेमाल कमांड सबस्टीट्यूशन के लिए बिल्कुल नहीं होता।"
  ]
}
